INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (192, 137029, 10, 208, '生命里云淡风清的日子', '生命里云淡风清的日子
<br>我和言樱一直是很好的朋友。我们如影随形，心有灵犀，喜欢相同的事物，不用开口就心领神会。但我们又是截然不同的，她温柔沉静，似一泓碧水；而我活泼开朗，阳光般灿烂。我们就像一株并蒂莲，彼此是对方身体的一部分，却又在同一个枝头上开着不同色的花。人们总喜欢把我俩看作一个人，静若处子，动如脱兔，有着很完美的双子性格。
<br>最初和林忆交往的时候我们俩也是像一个人一样。林忆是那种很理想的男生。确切一点说，应该是我理想中的男生。他有着明净如春水般的眼睛，微笑时露出一排雪白的牙齿，还有一张干净俊朗的男孩子的脸。我想言樱也喜欢他吧？尽管她从不肯承认。
<br>或许是缘分吧，新学期排座位的时候，言樱被安排坐在林忆前面，而我坐在他的左后侧。于是林忆就可以同时领略两种不同的风景――言樱的温柔，我的活泼。我不知道他更喜欢哪一个，因为他对每一个都是淡淡的，很友好，也很宽容我们小女孩式的耍赖和任性。但因为言樱和林忆的位子靠得很近，他们就有了更多的接触机会。
<br>此后我常常看到言樱转过头来和林忆讨论数学题目。每当此时，言樱脸上的笑容总是那么灿烂，像一朵开放在微风中的蔷薇花。即使从侧面看，我也能觉察出林忆眼中流淌着的温柔笑意。不知从什么时候起，我开始反感这样的画面，以及言樱在林忆面前流露出的刁蛮任性。我不明白为什么一贯温柔矜持的言樱惟独会对林忆这样，而且我不喜欢她那种娇嗔甜蜜的表情。
<br>但我想林忆喜欢吧。是的，在我们两人之中，他似乎更喜欢言樱。他从不主动和我说话，也没有任何思想的交流；而面对言樱，他就开朗自如得多，连笑容都明显的灿烂。我不得不承认言樱比我聪明，该柔时柔，该刁时刁，撒娇都比我撒得好。
<br>可是我又有一种很奇怪的直觉，――林忆喜欢我。要不然他为什么会不厌其烦地为我讲解数学题，要不然他为什么会每天放学后过街为我买巧克力冰淇淋，要不然他为什么会那么宽容我的一切无理取闹，和我说话时，他眼中那朵灿烂的火花是为我而开的吗？
<br>也许这只是我的自作多情。他总是把自己的感情掩藏得很好，他脸上的微笑永远是那么恬淡如水，没有一丝波澜。于是我只能猜，猜他一个眼神一个动作所包含的感情，却越猜越觉得自己错了。他喜欢的该是那种温柔的女生吧，偶尔撒撒娇发发小脾气。言樱就是这样的女孩子。而我很笨，不淑女也不温柔，想学言樱的娇柔却只能是东施效颦。于是我只能闷闷不乐地欣赏言樱与林忆交换眼神时的默契，他们的笑脸相互辉映，阳光般灿烂。那是一幅如此美丽的画面，却深深地刺痛了我的眼。
<br>那一段时间我常常翻来覆去地做同一个梦，我梦见言樱和林忆头挨着头亲密无间地坐在前排的座位上，他们脸上的笑容是我所熟悉的。他们默契的眼神和暧昧的笑声让我的心一抽一抽地疼。我想逃，逃到看不见他们的地方。可是言樱的笑声一直一直追着我，她温柔似水的眼睛望着我问，Summer，你不高兴吗？我说不，我很为你们开心。可是你为什么不笑呢？是啊，我为什么不笑呢？我想笑，可是我笑不出来。我急得想哭，言樱在看着我呢，快笑呀快笑呀！
<br>每一次醒来的时候我都告诉自己这只是个梦，可是内心深处的恐慌还是会像电流一般击中我。因为我越来越分不清这究竟是梦境还是现实了。每天早晨坐在教室里言樱和林忆相视含笑的眼神就会让我回到那梦境，我的心会忍不住地发酸。我试图让自己变得开朗起来，回到从前那种阳光灿烂的心态，可是没有用，他们都是我爱得最深的人。我甚至没有办法嫉妒她。
<br>我不知道冰雪聪明的言樱是否发现了这层微妙的情绪，她的心绪也莫名地变得很坏。每一次我与林忆谈得很开心，她就会很长一段时间不理睬我。她的任性和小性子开始变本加厉地增长，不复从前的温柔善解人意。我们的友情莫名其妙地失去了从前的和谐，我们俩早已分裂成了两个人。而我、言樱、林忆，我们是三角形的三个端点，只有两个点可以在同一条直线上。
<br>我觉得我们在上演着一出俗套的闹剧――两个很要好的女孩子喜欢上同一个男生，并且为他心存芥蒂。不同的是，我们都不愿意对方受到伤害，都在拼命地努力维系着，无力而苍白的友谊。但是我了解言樱的性格，她其实是一个很要强很倔强的女孩子，认准了的事就不会让步。那么，就让我退出吧！
<br>我开始变得沉默。尽量不和林忆说话，也避免习惯性地眺望他座位的方向。和言樱面对面坐着，我却很努力地笑，一直一直笑，勉强且做作。我怕我的心事会破坏我们两人的友情，或者，他和她的。
<br>林忆是很迟钝的。他丝毫没有觉察出我的沉默。或者说，他根本就没有心思去追究我沉默的原因。他依旧像从前那样沉默寡言，不动声色。但是有一天他突然带来了一叠很漂亮的彩纸，是用来折千纸鹤的，花花绿绿的颜色。他带着一贯的淡淡的笑容要我挑我喜欢的颜色。我的心很快地跳了一下。我曾经对他说我喜欢千纸鹤，我说我不会折，想让他折一些送我。那时侯只是随口说说，我根本没奢望他会把我的话记在心上，再说他怎么可能会折千纸鹤呢！
<br>可是我没有想到他真的会履行他的承诺。那一刻我的心中漫过一阵很汹涌的感动。瞬间我重又恢复了从前的顽皮和任性，我说我每一种颜色都要。他似乎很无奈地叹了一口气，笑着说好吧，我的小公主。那一刻他的表情他的语气让我明白了幸福的含义。于是那一整天，他用每一节上课的时间为我折千纸鹤，每折完一只，他就放到我的桌角上。一只，两只，三只……很快的，我的桌上堆了厚厚的一层纸鹤，五彩缤纷，一如我明丽的心情。
<br>我用手轻轻地一只一只抚摸那些纸鹤，我的手指划过它们平整的棱角，精致的翅膀，仿佛触摸得到折叠它们的人细腻的心思。我让自己相信这是林忆为我折的，特意为我折的，是的，不只是为了履行他的承诺。我真的希望是这样。那一刻，我很陶醉，陶醉在这一份难得的快乐之中。
<br>就在这个时候，言樱转过头来了。她惊喜地望见林忆桌上那一叠五色的彩纸，用很亲昵的语气说哇，好漂亮，你会折千纸鹤呀？教教我吧！她的声音那么婉转，那么动听，却尖锐地划破了我的心。林忆很温和地笑着点点头。我看见他们的头挨得很近，脸上的微笑灿烂如花，眼神中温柔流动。恍惚间我又一次回到了梦境。言樱脸上的笑容多么美丽呀！
<br>我的大脑一片空白，却突然有一种笑的欲望。我想笑，笑自己的天真，笑自己的自作多情。是的，他只不过是为了履行他的承诺，我竟忘了这只是他的习惯，他的有求必应的好习惯。我看了一眼桌面上的千纸鹤，又看了一眼笑靥如花的言樱，它们是多么适合她呀！
<br>我突然有一种冲动，把千纸鹤送给真正有资格拥有它们的主人。我最后一次久久地注视着它们，我真舍不得，可是，我告诉自己，它们是不属于我的。下课的时候，我把一大堆千纸鹤抱在怀里走到言樱座位面前，然后，一扬手，五彩缤纷的千纸鹤就这样纷纷扬扬地洒落下来，飞舞着从天而降，落到她的桌上。言樱惊异地抬起头望着我，我笑着说，这些是送给你的。其实，我想补上一句，是他送给你的。一个久违的很清朗很纯粹的微笑在她的脸上绽开。她什么都没说，只是轻轻地握住了我的手。
<br>然后言樱把千纸鹤一捧，放在林忆的桌上。面对我不解的眼神，她笑着说，我并不喜欢千纸鹤，家里还有一大串呢，不过，如果你喜欢的话，我可以送你呢。我笑了，说好啊，你一定要记得哦！我们相视而笑，彼此都有一种如释重负的轻松。我感到我们之间那种失去很久的理解和真诚又回来了。
<br>第二天我在教室的垃圾桶里看到了那些千纸鹤。我不知道是谁把它们丢进去的，我不想知道，也没有必要知道了。因为我、言樱、林忆，我们三个人都很好，我们很快乐，真的。你知道那种宽容单纯，没有猜忌的友谊带来的快乐吗，会好象天空一样宽广，蓝的那样纯粹，没有一丝阴霾。我想，在我们年轻的时候，那些有至亲至爱的朋友相伴的日子，就是生命里云淡风清的日子吧？', '生命里云淡风清的日子

